class Solution:
    def countPairs(self, nums):
        def almost_equal(x, y):
            sx, sy = str(x), str(y)
            L = max(len(sx), len(sy))
            sx = sx.zfill(L)
            sy = sy.zfill(L)
            diff = [i for i in range(L) if sx[i] != sy[i]]
            if len(diff) == 0:
                return True
            if len(diff) == 2:
                i, j = diff
                return sx[i] == sy[j] and sx[j] == sy[i]
            return False

        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                if almost_equal(nums[i], nums[j]):
                    count += 1
        return count

