class Solution:
    def countPairs(self, nums):
        def variants(x):
            s = str(x)
            L = len(s)
            res = {x}
            for i in range(L):
                for j in range(i + 1, L):
                    lst = list(s)
                    lst[i], lst[j] = lst[j], lst[i]
                    res.add(int(''.join(lst)))
            return res

        vs = [variants(v) for v in nums]
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                if nums[j] in vs[i] or nums[i] in vs[j]:
                    count += 1
        return count

