var countPairs = function(nums) {
    function variants(x) {
        const s = String(x);
        const L = s.length;
        const res = new Set([x]);
        for (let i = 0; i < L; i++) {
            for (let j = i + 1; j < L; j++) {
                const arr = s.split('');
                const tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
                res.add(parseInt(arr.join(''), 10));
            }
        }
        return res;
    }
    const n = nums.length;
    const vs = nums.map(variants);
    let count = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            if (vs[i].has(nums[j]) || vs[j].has(nums[i])) count++;
        }
    }
    return count;
};
